package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
)

type User struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
}

var users = map[string]User{
	"1": {ID: 1, Name: "Alex", Email: "alex@example.com"},
	// TODO: add user with id "7"
}

func userHandler(w http.ResponseWriter, r *http.Request) {
	id := r.URL.Query().Get("id")
	user, ok := users[id]
	if !ok {
		w.WriteHeader(http.StatusNotFound)
		fmt.Fprintln(w, `{"error":"not found"}`)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	for _, id := range []string{"1", "7", "99"} {
		req := httptest.NewRequest("GET", "/?id="+id, nil)
		w := httptest.NewRecorder()
		userHandler(w, req)
		fmt.Printf("[%d] %s", w.Code, w.Body.String())
	}
}

package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"strings"
)

type CreateUserRequest struct {
	Name  string `json:"name"`
	Email string `json:"email"`
}

func createUserHandler(w http.ResponseWriter, r *http.Request) {
	defer r.Body.Close()

	var req CreateUserRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		w.WriteHeader(http.StatusBadRequest)
		fmt.Fprintln(w, `{"error":"invalid body"}`)
		return
	}

	w.WriteHeader(http.StatusCreated)
	fmt.Fprintf(w, "Created user: %s (%s)\n", req.Name, req.Email)
}

func main() {
	body := `{"name":"Alex","email":"alex@example.com"}`
	req := httptest.NewRequest("POST", "/users", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	createUserHandler(w, req)
	fmt.Printf("Status: %d\n", w.Code)
	fmt.Print(w.Body.String())
}

