	for _, method := range []string{"GET", "POST", "DELETE"} {
		req := httptest.NewRequest(method, "/users", nil)
		w := httptest.NewRecorder()
		usersHandler(w, req)
		fmt.Printf("%s [%d]: %s", method, w.Code, w.Body.String())
	}
}

